import type { FC } from 'react';
import React from 'react';

import type { CollapsableTimelineProps } from '../../Timeline.types';
import { VerticalContent } from '../VerticalContent';

export const CollapsableVerticalTimeline: FC<CollapsableTimelineProps> = ({ steps }) => {
	const stepsLength = steps.length;

	if (!stepsLength) {
		return null;
	}

	return (
		<>
			{steps.map(step => (
				<VerticalContent {...step} key={step.id} type="active" position="middle" />
			))}
		</>
	);
};
